import jwt
from datetime import datetime, timedelta

def generate_jwt(user_id, role):
    payload = {
        'user_id': user_id,
        'role': role,
        'exp': datetime.utcnow() + timedelta(minutes=30)
    }
    
    return jwt.encode(payload, key='secret_key', algorithm='HS256')

def verify_jwt(token):
    try:
        decoded_token = jwt.decode(token, key='secret_key', algorithms=['HS256'])
        
        if decoded_token['exp'] < datetime.utcnow():
            raise jwt.ExpiredSignatureError('Token has expired')
            
        return decoded_token
    except jwt.InvalidTokenError as e:
        print(f'Invalid token: {e}')
        return None

# Example usage
user_id = 1
role = 'admin'
token = generate_jwt(user_id, role)
print(token)

decoded_token = verify_jwt(token)
if decoded_token is not None:
    print(decoded_token['user_id'])